const SESSION_ID = 'YOUR_SESSION_ID';
const OWNER_PHONE = 'YOUR_PHONE';

const order = $input.first().json.body || $input.first().json;

const orderId = order.id || order.number || 'N/A';
const status = order.status || 'new';
const total = order.total || '0.00';
const currency = order.currency || 'USD';

const billing = order.billing || {};
const customerName = (billing.first_name || '') + ' ' + (billing.last_name || '');
const customerEmail = billing.email || '';
const customerPhone = (billing.phone || '').replace(/[^0-9]/g, '');

const items = (order.line_items || []).map(item =>
  item.name + ' x' + item.quantity
).join(', ');

const ownerMsg = `New Order #${orderId}!\n\nCustomer: ${customerName.trim()}\nItems: ${items}\nTotal: ${currency} ${total}\nStatus: ${status}\n\nCheck your WooCommerce dashboard for details.`;

const results = [{
  json: {
    session_id: SESSION_ID,
    chat_id: OWNER_PHONE + '@c.us',
    message: ownerMsg,
    type: 'owner_notification',
    order_id: orderId
  }
}];

if (customerPhone && customerPhone.length >= 7) {
  const customerMsg = `Hi ${customerName.trim() || 'there'}! Your order #${orderId} has been received. Total: ${currency} ${total}. We'll update you when it ships. Thank you!`;
  results.push({
    json: {
      session_id: SESSION_ID,
      chat_id: customerPhone + '@c.us',
      message: customerMsg,
      type: 'customer_confirmation',
      order_id: orderId
    }
  });
}

return results;

const items = $input.all();
const orderId = $('Format Order').first().json.order_id;
return [{ json: { status: 'notified', order_id: orderId, messages_sent: items.length } }];
